class UserDB:
    def __init__(self):
        self.users = {}
        self.next_id = 1

    def create_user(self, username, email):
        # Bug: No duplicate check
        user_id = str(self.next_id)
        self.users[user_id] = {
            'id': user_id,
            'username': username,
            'email': email
        }
        self.next_id += 1
        return user_id

    def get_user(self, user_id):
        # Bug: Type mismatch (user_id might be int)
        return self.users.get(user_id)
